class Solution:
    def treeHeight(self, nodes):
        heights = [0] * len(nodes)
        for i, node in enumerate(nodes):
            if node[1] != -1:
                heights[i] += 1 + self.treeHeight(nodes[node[1]])
            if node[2] != -1:
                heights[i] += 1 + self.treeHeight(nodes[node[2]])
        return heights

